import"./chunk-JS3ZFT6L.js";var e={id:1,title:"\u0645\u0642\u062F\u0645\u0629 \u0627\u0644\u0643\u0648\u0631\u0633",titleEn:"Course Introduction",level:"\u0645\u0628\u062A\u062F\u0626",levelEn:"Beginner",intro:"\u0623\u0647\u0644\u0627\u064B \u0628\u0643 \u0641\u064A \u0643\u0648\u0631\u0633 \u0623\u0646\u062C\u0648\u0644\u0627\u0631 v22! \u0647\u0630\u0627 \u0627\u0644\u0642\u0633\u0645 \u064A\u062C\u0647\u0651\u0632\u0643 \u0644\u0644\u0628\u062F\u0627\u064A\u0629 \u2014 \u0644\u0627 \u064A\u0648\u062C\u062F \u0643\u0648\u062F \u0628\u0639\u062F\u060C \u0628\u0644 \u0646\u062A\u0639\u0631\u0651\u0641 \u0639\u0644\u0649: \u0645\u0627 \u0647\u0648 \u0623\u0646\u062C\u0648\u0644\u0627\u0631\u060C \u0645\u0627 \u0627\u0644\u0630\u064A \u0633\u062A\u0628\u0646\u064A\u0647\u060C \u0645\u0627 \u0627\u0644\u062C\u062F\u064A\u062F \u0641\u064A \u0627\u0644\u0625\u0635\u062F\u0627\u0631 22\u060C \u0648\u0627\u0644\u0641\u0631\u0642 \u0628\u064A\u0646\u0647 \u0648\u0628\u064A\u0646 React \u0648Vue\u060C \u0648\u0643\u064A\u0641 \u062A\u0633\u062A\u0641\u064A\u062F \u0645\u0646 \u0647\u0630\u0627 \u0627\u0644\u0643\u0648\u0631\u0633 \u0628\u0623\u0641\u0636\u0644 \u0637\u0631\u064A\u0642\u0629.",introEn:"Welcome to the Angular v22 course! This section gets you ready to start \u2014 no code yet. We'll cover: what Angular is, what you'll build, what's new in v22, how it compares to React and Vue, and how to get the most out of this course.",lessons:["\u0645\u0631\u062D\u0628\u0627\u064B\u060C \u0623\u0646\u0627 \u0645\u0635\u0637\u0641\u0649 \u0633\u0642\u0644\u0649","\u0645\u0627\u0630\u0627 \u0633\u062A\u0628\u0646\u064A \u0641\u064A \u0647\u0630\u0627 \u0627\u0644\u0643\u0648\u0631\u0633","\u0627\u0644\u0645\u062A\u0637\u0644\u0628\u0627\u062A \u0648\u062E\u0631\u064A\u0637\u0629 \u0627\u0644\u0643\u0648\u0631\u0633","\u0646\u0638\u0631\u0629 \u0639\u0627\u0645\u0629 \u0639\u0644\u0649 \u0623\u0646\u062C\u0648\u0644\u0627\u0631 v22 \u2014 \u0639\u0635\u0631 Signals","\u0627\u0644\u062C\u062F\u064A\u062F \u0641\u064A v22 (Signal Forms\u060C OnPush\u060C Zoneless)","\u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0645\u0642\u0627\u0628\u0644 React \u0645\u0642\u0627\u0628\u0644 Vue","\u0645\u062A\u0649 \u062A\u0633\u062A\u062E\u062F\u0645 \u0623\u0646\u062C\u0648\u0644\u0627\u0631","\u0643\u064A\u0641 \u062A\u0633\u062A\u0641\u064A\u062F \u0645\u0646 \u0647\u0630\u0627 \u0627\u0644\u0643\u0648\u0631\u0633"],lessonsEn:["Hello, I'm Mostafa Saqly","What You Will Build","Prerequisites & Course Roadmap","Angular v22 Overview \u2014 The Signal-First Era","What's New in v22 (Signal Forms, OnPush by Default, Zoneless)","Angular vs React vs Vue","When to Use Angular","How to Get the Most Out of This Course"],content:[{type:"heading",text:"\u{1F44B} \u0645\u0631\u062D\u0628\u0627\u064B\u060C \u0623\u0646\u0627 \u0645\u0635\u0637\u0641\u0649 \u0633\u0642\u0644\u0649"},{type:"paragraph",text:"\u0635\u0645\u0651\u0645\u062A \u0647\u0630\u0627 \u0627\u0644\u0643\u0648\u0631\u0633 \u0644\u0645\u0633\u0627\u0639\u062F\u0629 \u0623\u064A \u0634\u062E\u0635 \u064A\u0631\u064A\u062F \u062A\u0639\u0644\u0651\u0645 \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0645\u0646 \u0627\u0644\u0635\u0641\u0631 \u0628\u0623\u0633\u0644\u0648\u0628 \u0639\u0631\u0628\u064A \u0648\u0627\u0636\u062D \u0648\u0645\u0646\u0638\u0651\u0645. \u062C\u0645\u0651\u0639\u062A \u0644\u0643 \u0623\u0641\u0636\u0644 \u0627\u0644\u0645\u0645\u0627\u0631\u0633\u0627\u062A \u0648\u0627\u0644\u062A\u0642\u0646\u064A\u0627\u062A \u0627\u0644\u062D\u062F\u064A\u062B\u0629 \u0644\u0623\u0646\u062C\u0648\u0644\u0627\u0631 v22 \u0641\u064A \u0645\u0643\u0627\u0646 \u0648\u0627\u062D\u062F \u2014 \u0628\u062F\u0648\u0646 \u062A\u0634\u062A\u0651\u062A."},{type:"paragraph",text:"\u0627\u0644\u0641\u0643\u0631\u0629 \u0628\u0633\u064A\u0637\u0629: \u062A\u0648\u0641\u064A\u0631 \u0648\u0642\u062A\u0643 \u0645\u0646 \u0627\u0644\u0628\u062D\u062B \u0641\u064A \u0627\u0644\u0645\u0646\u062A\u062F\u064A\u0627\u062A \u0648\u0645\u0634\u0627\u0647\u062F\u0629 \u0639\u0634\u0631\u0627\u062A \u0627\u0644\u0641\u064A\u062F\u064A\u0648\u0647\u0627\u062A. \u0643\u0644 \u0645\u0627 \u062A\u062D\u062A\u0627\u062C\u0647 \u0645\u0648\u062C\u0648\u062F \u0647\u0646\u0627 \u2014 \u0645\u0631\u062A\u0651\u0628\u060C \u0645\u062E\u062A\u0635\u0631\u060C \u0648\u0642\u0627\u0628\u0644 \u0644\u0644\u062A\u0637\u0628\u064A\u0642 \u0645\u0628\u0627\u0634\u0631\u0629\u064B."},{type:"cta",text:"\u0644\u0648 \u0645\u062D\u062A\u0627\u062C \u062A\u062F\u0631\u064A\u0628 \u0645\u062A\u062E\u0635\u0635 \u0639\u0644\u0649 \u0645\u0633\u0627\u0631 \u0643\u0627\u0645\u0644\u060C",linkLabel:"\u0627\u062F\u062E\u0644 \u0645\u0646 \u0647\u0646\u0627 \u2192",link:"https://saqly.com/individual-training"},{type:"tip",text:"\u0627\u0642\u0631\u0623 \u0648\u0637\u0628\u0651\u0642. \u0643\u0644 \u062F\u0631\u0633 \u0641\u064A\u0647 \u0623\u0645\u062B\u0644\u0629 \u0639\u0645\u0644\u064A\u0629 \u062C\u0627\u0647\u0632\u0629 \u0644\u0644\u062A\u0634\u063A\u064A\u0644 \u0639\u0644\u0649 \u062C\u0647\u0627\u0632\u0643 \u0645\u0628\u0627\u0634\u0631\u0629\u064B."},{type:"heading",text:"1. \u0645\u0627\u0630\u0627 \u0633\u062A\u0628\u0646\u064A \u0641\u064A \u0647\u0630\u0627 \u0627\u0644\u0643\u0648\u0631\u0633"},{type:"paragraph",text:"\u0633\u062A\u0628\u0646\u064A \u0641\u064A \u0646\u0647\u0627\u064A\u0629 \u0627\u0644\u0643\u0648\u0631\u0633 \u0645\u0634\u0631\u0648\u0639\u064E\u064A\u0646 \u0643\u0627\u0645\u0644\u064E\u064A\u0646 \u062C\u0627\u0647\u0632\u064E\u064A\u0646 \u0644\u0645\u0639\u0631\u0636 \u0623\u0639\u0645\u0627\u0644\u0643: \u0644\u0648\u062D\u0629 \u062A\u062D\u0643\u0645 \u0625\u062F\u0627\u0631\u064A\u0629 (Admin Dashboard) \u0648\u0645\u062A\u062C\u0631 \u0625\u0644\u0643\u062A\u0631\u0648\u0646\u064A \u0645\u0635\u063A\u0651\u0631 (E-Commerce Mini App) \u2014 \u0628\u0627\u0644\u0625\u0636\u0627\u0641\u0629 \u0625\u0644\u0649 \u0639\u0634\u0631\u0627\u062A \u0627\u0644\u0623\u0645\u062B\u0644\u0629 \u0627\u0644\u0635\u063A\u064A\u0631\u0629 \u0639\u0644\u0649 \u0643\u0644 \u0645\u0641\u0647\u0648\u0645."},{type:"list",items:["\u{1F5C2}\uFE0F \u0627\u0644\u0645\u0634\u0631\u0648\u0639 \u0627\u0644\u0623\u0648\u0644: \u0644\u0648\u062D\u0629 \u062A\u062D\u0643\u0645 \u2014 \u0639\u0631\u0636 \u0628\u064A\u0627\u0646\u0627\u062A API\u060C \u0628\u062D\u062B\u060C \u0625\u0636\u0627\u0641\u0629/\u062A\u0639\u062F\u064A\u0644/\u062D\u0630\u0641\u060C \u0646\u0645\u0627\u0630\u062C Signal Forms\u060C \u062D\u0645\u0627\u064A\u0629 \u0627\u0644\u0645\u0633\u0627\u0631\u0627\u062A","\u{1F6D2} \u0627\u0644\u0645\u0634\u0631\u0648\u0639 \u0627\u0644\u062B\u0627\u0646\u064A: \u0645\u062A\u062C\u0631 \u0645\u0635\u063A\u0651\u0631 \u2014 \u0635\u0641\u062D\u0627\u062A \u0645\u0646\u062A\u062C\u0627\u062A\u060C \u0633\u0644\u0651\u0629 \u0645\u0634\u062A\u0631\u064A\u0627\u062A\u060C \u0625\u062F\u0627\u0631\u0629 \u0627\u0644\u0643\u0645\u064A\u0627\u062A\u060C \u062A\u062E\u0632\u064A\u0646 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u0645\u062D\u0644\u064A\u0627\u064B","\u26A1 \u0623\u0645\u062B\u0644\u0629 \u062A\u0637\u0628\u064A\u0642\u064A\u0629: Signals\u060C HTTP\u060C Routing\u060C Forms\u060C RxJS\u060C SSR\u060C \u0648\u0623\u0643\u062B\u0631"]},{type:"heading",text:"2. \u0627\u0644\u0645\u062A\u0637\u0644\u0628\u0627\u062A \u0648\u062E\u0631\u064A\u0637\u0629 \u0627\u0644\u0643\u0648\u0631\u0633"},{type:"paragraph",text:"\u0627\u0644\u0645\u0634\u0643\u0644\u0629: \u0643\u062B\u064A\u0631 \u0645\u0646 \u0627\u0644\u0646\u0627\u0633 \u064A\u0628\u062F\u0624\u0648\u0646 \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0648\u0639\u0646\u062F\u0647\u0645 \u0641\u062C\u0648\u0627\u062A \u0641\u064A \u0627\u0644\u0645\u0639\u0631\u0641\u0629 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0629\u060C \u0641\u064A\u064F\u0635\u0627\u0628\u0648\u0646 \u0628\u0627\u0644\u0625\u062D\u0628\u0627\u0637 \u0639\u0646\u062F \u0623\u0648\u0644 \u062A\u062D\u062F\u064D\u0651. \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0625\u0637\u0627\u0631 \u0639\u0645\u0644 \u0645\u062A\u0643\u0627\u0645\u0644 \u2014 \u0648\u0647\u0648 \u064A\u0628\u0646\u064A \u0639\u0644\u0649 HTML \u0648CSS \u0648TypeScript \u0648\u0645\u0641\u0627\u0647\u064A\u0645 \u0627\u0644\u0628\u0631\u0645\u062C\u0629 \u0627\u0644\u0643\u0627\u0626\u0646\u064A\u0629."},{type:"paragraph",text:"\u0627\u0644\u062D\u0644: \u0642\u0628\u0644 \u0627\u0644\u0628\u062F\u0621\u060C \u062A\u0623\u0643\u0651\u062F \u0623\u0646\u0643 \u0645\u0631\u062A\u0627\u062D \u0645\u0639 \u0647\u0630\u0647 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0627\u062A:"},{type:"list",items:["HTML \u0648 CSS \u2014 \u0627\u0644\u0628\u0646\u064A\u0629 \u0648\u0627\u0644\u062A\u0635\u0645\u064A\u0645","TypeScript \u0627\u0644\u0623\u0633\u0627\u0633\u064A \u2014 \u0627\u0644\u0623\u0646\u0648\u0627\u0639\u060C \u0627\u0644\u0648\u0627\u062C\u0647\u0627\u062A\u060C \u0627\u0644\u062F\u064A\u0643\u0648\u0631\u0627\u062A\u0648\u0631\u0627\u062A","\u0645\u0641\u0627\u0647\u064A\u0645 OOP \u2014 \u0627\u0644\u0635\u0641\u0648\u0641 (Classes) \u0648\u0627\u0644\u0648\u0631\u0627\u062B\u0629","Node.js (v22+) \u0648 npm \u2014 \u0625\u062F\u0627\u0631\u0629 \u0627\u0644\u062D\u0632\u0645","JavaScript \u0627\u0644\u062D\u062F\u064A\u062B\u0629 \u2014 async/await\u060C Promises\u060C ES Modules"]},{type:"warning",text:"\u0625\u0630\u0627 \u0643\u0627\u0646 TypeScript \u063A\u0631\u064A\u0628\u0627\u064B \u0639\u0644\u064A\u0643 \u062A\u0645\u0627\u0645\u0627\u064B\u060C \u0627\u0642\u0636\u0650 \u0633\u0627\u0639\u062A\u064A\u0646 \u0641\u064A \u0623\u0633\u0627\u0633\u064A\u0627\u062A\u0647 \u0623\u0648\u0644\u0627\u064B. \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0645\u0643\u062A\u0648\u0628 \u0628\u0640 TypeScript \u0648\u0644\u064A\u0633 \u0628\u0640 JavaScript \u0627\u0644\u0639\u0627\u062F\u064A\u0629."},{type:"paragraph",text:"\u062E\u0631\u064A\u0637\u0629 \u0627\u0644\u0643\u0648\u0631\u0633: 25 \u0642\u0633\u0645\u0627\u064B \u2014 \u0645\u0646 \u0623\u0633\u0627\u0633\u064A\u0627\u062A \u0627\u0644\u0645\u0643\u0648\u0651\u0646\u0627\u062A \u0648\u062D\u062A\u0649 \u0627\u0644\u0646\u0634\u0631 \u0648\u0627\u0644\u0627\u062E\u062A\u0628\u0627\u0631\u0627\u062A \u2014 \u0645\u0639 \u0645\u0634\u0631\u0648\u0639\u064E\u064A\u0646 \u062A\u0637\u0628\u064A\u0642\u064A\u064E\u0651\u064A\u0646 \u0641\u064A \u0627\u0644\u0646\u0647\u0627\u064A\u0629."},{type:"heading",text:"3. \u0646\u0638\u0631\u0629 \u0639\u0627\u0645\u0629 \u0639\u0644\u0649 \u0623\u0646\u062C\u0648\u0644\u0627\u0631 v22 \u2014 \u0639\u0635\u0631 Signals"},{type:"paragraph",text:"\u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0625\u0637\u0627\u0631 \u0639\u0645\u0644 \u0645\u062A\u0643\u0627\u0645\u0644 (Full Framework) \u0645\u0646 Google \u0644\u0628\u0646\u0627\u0621 \u062A\u0637\u0628\u064A\u0642\u0627\u062A \u0648\u064A\u0628 \u0645\u0646 \u0627\u0644\u0645\u0624\u0633\u0633\u0627\u062A. \u064A\u062E\u062A\u0644\u0641 \u0639\u0646 React \u0648Vue \u0641\u064A \u0623\u0646\u0647 \u064A\u0623\u062A\u064A \u0628\u0643\u0644 \u0634\u064A\u0621 \u062C\u0627\u0647\u0632\u0627\u064B: \u0627\u0644\u062A\u0648\u062C\u064A\u0647\u060C \u0627\u0644\u0646\u0645\u0627\u0630\u062C\u060C HTTP\u060C \u0627\u0644\u0627\u062E\u062A\u0628\u0627\u0631\u0627\u062A\u060C \u0625\u062F\u0627\u0631\u0629 \u0627\u0644\u062D\u0627\u0644\u0629 \u2014 \u062F\u0648\u0646 \u0627\u0644\u062D\u0627\u062C\u0629 \u0644\u0645\u0643\u062A\u0628\u0627\u062A \u062E\u0627\u0631\u062C\u064A\u0629."},{type:"list",items:["\u0627\u0644\u0645\u0643\u0648\u0651\u0646\u0627\u062A (Components) \u2014 \u0644\u0628\u0646\u0627\u062A \u0627\u0644\u0628\u0646\u0627\u0621 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0629\u060C \u0645\u0643\u062A\u0648\u0628\u0629 \u0628\u0640 TypeScript + HTML + CSS","Signals \u2014 \u0627\u0644\u0646\u0638\u0627\u0645 \u0627\u0644\u062A\u0641\u0627\u0639\u0644\u064A \u0627\u0644\u062C\u062F\u064A\u062F \u0644\u0625\u062F\u0627\u0631\u0629 \u0627\u0644\u062D\u0627\u0644\u0629 \u0628\u0643\u0641\u0627\u0621\u0629","Standalone Components \u2014 \u0645\u0643\u0648\u0651\u0646\u0627\u062A \u0645\u0633\u062A\u0642\u0644\u0629 \u0628\u062F\u0648\u0646 NgModule","Dependency Injection \u2014 \u062D\u0642\u0646 \u0627\u0644\u062A\u0628\u0639\u064A\u0627\u062A \u0627\u0644\u0645\u062F\u0645\u062C","Angular CLI \u2014 \u0623\u062F\u0627\u0629 \u0633\u0637\u0631 \u0623\u0648\u0627\u0645\u0631 \u0642\u0648\u064A\u0629 \u062A\u064F\u0646\u0634\u0626 \u0648\u062A\u0628\u0646\u064A \u0648\u062A\u062E\u062A\u0628\u0631"]},{type:"tip",text:"\u0623\u0646\u062C\u0648\u0644\u0627\u0631 v22 \u064A\u064F\u0633\u0645\u0651\u0649 '\u0639\u0635\u0631 Signals' \u0644\u0623\u0646 (Signals) \u0623\u0635\u0628\u062D\u062A \u0627\u0644\u0637\u0631\u064A\u0642\u0629 \u0627\u0644\u0627\u0641\u062A\u0631\u0627\u0636\u064A\u0629 \u0644\u0625\u062F\u0627\u0631\u0629 \u0627\u0644\u062D\u0627\u0644\u0629 \u0641\u064A \u0623\u064A \u0645\u0643\u0648\u0651\u0646 \u062C\u062F\u064A\u062F."},{type:"heading",text:"4. \u0627\u0644\u062C\u062F\u064A\u062F \u0641\u064A v22"},{type:"subheading",text:"\u26A1 Signal Forms \u2014 \u0627\u0644\u0646\u0645\u0627\u0630\u062C \u0627\u0644\u062A\u0641\u0627\u0639\u0644\u064A\u0629 \u0627\u0644\u062C\u062F\u064A\u062F\u0629"},{type:"paragraph",text:"\u0627\u0644\u0645\u0634\u0643\u0644\u0629: \u0627\u0644\u0646\u0645\u0627\u0630\u062C \u0641\u064A \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0643\u0627\u0646\u062A \u062F\u0627\u0626\u0645\u0627\u064B \u0645\u0639\u0642\u0651\u062F\u0629 \u2014 \u0625\u0645\u0627 Template-Driven (\u0635\u0639\u0628 \u0627\u0644\u0627\u062E\u062A\u0628\u0627\u0631) \u0623\u0648 Reactive Forms (\u0643\u0648\u062F \u0637\u0648\u064A\u0644). Signal Forms \u062A\u064F\u0628\u0633\u0651\u0637 \u0643\u0644 \u0630\u0644\u0643."},{type:"paragraph",text:"\u0627\u0644\u062D\u0644: Signal Forms \u0623\u0635\u0628\u062D\u062A \u0627\u0644\u0637\u0631\u064A\u0642\u0629 \u0627\u0644\u0627\u0641\u062A\u0631\u0627\u0636\u064A\u0629 \u0641\u064A v22 \u2014 \u0646\u0645\u0627\u0630\u062C \u062A\u064F\u0628\u0646\u0649 \u0639\u0644\u0649 Signals\u060C \u0623\u0642\u0644 \u0643\u0648\u062F\u0627\u064B\u060C \u0648\u0623\u0633\u0647\u0644 \u0644\u0644\u0627\u062E\u062A\u0628\u0627\u0631."},{type:"code",code:`import { signalForm, Validators } from '@angular/forms';

// Signal Form \u2014 \u062C\u062F\u064A\u062F \u0641\u064A v22
const form = signalForm({
  name: ['', Validators.required],
  email: ['', [Validators.required, Validators.email]],
});

// \u0642\u0631\u0627\u0621\u0629 \u0627\u0644\u0642\u064A\u0645\u0629 \u0643\u0640 Signal
console.log(form.value()); // { name: '', email: '' }`},{type:"subheading",text:"\u{1F3AF} OnPush \u0643\u0627\u0633\u062A\u0631\u0627\u062A\u064A\u062C\u064A\u0629 \u0627\u0641\u062A\u0631\u0627\u0636\u064A\u0629"},{type:"paragraph",text:"\u0641\u064A v22\u060C \u0643\u0644 \u0645\u0643\u0648\u0651\u0646 \u062C\u062F\u064A\u062F \u064A\u064F\u0646\u0634\u0623 \u0628\u0627\u0633\u062A\u0631\u0627\u062A\u064A\u062C\u064A\u0629 OnPush \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B \u2014 \u0648\u0647\u0630\u0627 \u064A\u0639\u0646\u064A \u0623\u062F\u0627\u0621\u064B \u0623\u0641\u0636\u0644 \u0628\u062F\u0648\u0646 \u0623\u064A \u062C\u0647\u062F \u0625\u0636\u0627\u0641\u064A. \u0627\u0644\u0627\u0633\u062A\u0631\u0627\u062A\u064A\u062C\u064A\u0629 \u0627\u0644\u0642\u062F\u064A\u0645\u0629 'Default' \u0623\u064F\u0639\u064A\u062F\u062A \u062A\u0633\u0645\u064A\u062A\u0647\u0627 \u0625\u0644\u0649 'Eager'."},{type:"subheading",text:"\u{1F310} Zoneless \u0628\u0627\u0644\u0627\u0641\u062A\u0631\u0627\u0636\u064A"},{type:"paragraph",text:"\u0627\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0627\u0644\u062C\u062F\u064A\u062F\u0629 \u0641\u064A v22 \u0644\u0627 \u062A\u0633\u062A\u062E\u062F\u0645 Zone.js \u0628\u0634\u0643\u0644 \u0627\u0641\u062A\u0631\u0627\u0636\u064A. \u0647\u0630\u0627 \u064A\u064F\u062D\u0633\u0651\u0646 \u0627\u0644\u0623\u062F\u0627\u0621 \u0628\u0634\u0643\u0644 \u0645\u0644\u062D\u0648\u0638 \u0648\u064A\u064F\u0642\u0644\u0651\u0644 \u062D\u062C\u0645 \u0627\u0644\u062D\u0632\u0645\u0629."},{type:"list",items:["Signal Forms \u0645\u0633\u062A\u0642\u0631\u0629 \u0648\u0647\u064A \u0627\u0644\u0637\u0631\u064A\u0642\u0629 \u0627\u0644\u0627\u0641\u062A\u0631\u0627\u0636\u064A\u0629","OnPush \u0627\u0633\u062A\u0631\u0627\u062A\u064A\u062C\u064A\u0629 \u0627\u0641\u062A\u0631\u0627\u0636\u064A\u0629 \u0644\u0643\u0644 \u0645\u0643\u0648\u0651\u0646 \u062C\u062F\u064A\u062F","Zoneless \u0647\u0648 \u0627\u0644\u0625\u0639\u062F\u0627\u062F \u0627\u0644\u0627\u0641\u062A\u0631\u0627\u0636\u064A \u0644\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0627\u0644\u062C\u062F\u064A\u062F\u0629","Resource API \u0645\u0633\u062A\u0642\u0631\u0629 (resource, rxResource, httpResource)","Selectorless Components \u2014 \u0645\u0643\u0648\u0651\u0646\u0627\u062A \u0628\u062F\u0648\u0646 selector (\u062C\u062F\u064A\u062F)","Angular Aria \u2014 \u0625\u0645\u0643\u0627\u0646\u064A\u0629 \u0627\u0644\u0648\u0635\u0648\u0644 \u0645\u062F\u0645\u062C\u0629 (\u0645\u0633\u062A\u0642\u0631\u0629)","Navigation API \u2014 \u062F\u0639\u0645 Web Navigation API \u0641\u064A \u0627\u0644\u0640 Router"]},{type:"heading",text:"5. \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0645\u0642\u0627\u0628\u0644 React \u0645\u0642\u0627\u0628\u0644 Vue"},{type:"paragraph",text:"\u0627\u0644\u0645\u0634\u0643\u0644\u0629: \u0627\u0644\u0643\u062B\u064A\u0631 \u064A\u062A\u0633\u0627\u0621\u0644 '\u0645\u0627\u0630\u0627 \u0623\u062A\u0639\u0644\u0651\u0645\u061F' \u2014 \u0648\u0627\u0644\u062C\u0648\u0627\u0628 \u064A\u0639\u062A\u0645\u062F \u0639\u0644\u0649 \u0637\u0628\u064A\u0639\u0629 \u0627\u0644\u0645\u0634\u0631\u0648\u0639 \u0648\u062D\u062C\u0645 \u0627\u0644\u0641\u0631\u064A\u0642 \u0648\u0627\u0644\u0633\u064A\u0627\u0642."},{type:"list",items:["\u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u2014 \u0625\u0637\u0627\u0631 \u0639\u0645\u0644 \u0645\u062A\u0643\u0627\u0645\u0644\u060C TypeScript \u0623\u0648\u0644\u0627\u064B\u060C \u0645\u062B\u0627\u0644\u064A \u0644\u062A\u0637\u0628\u064A\u0642\u0627\u062A \u0627\u0644\u0645\u0624\u0633\u0633\u0627\u062A \u0648\u0627\u0644\u0641\u0631\u0642 \u0627\u0644\u0643\u0628\u064A\u0631\u0629","React \u2014 \u0645\u0643\u062A\u0628\u0629 \u0644\u0644\u0648\u0627\u062C\u0647\u0627\u062A\u060C \u0645\u0631\u0648\u0646\u0629 \u0639\u0627\u0644\u064A\u0629\u060C \u0646\u0638\u0627\u0645 \u0628\u064A\u0626\u064A \u0636\u062E\u0645\u060C \u0645\u062B\u0627\u0644\u064A \u0644\u0644\u0634\u0631\u0643\u0627\u062A \u0627\u0644\u0646\u0627\u0634\u0626\u0629 \u0648\u0627\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0627\u0644\u0645\u062A\u0646\u0648\u0639\u0629","Vue \u2014 \u0633\u0647\u0644 \u0627\u0644\u062A\u0639\u0644\u0645\u060C \u0645\u0632\u064A\u062C \u0645\u0646 \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0648React\u060C \u0645\u062B\u0627\u0644\u064A \u0644\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0627\u0644\u0645\u062A\u0648\u0633\u0637\u0629 \u0648\u0627\u0644\u062A\u0643\u0627\u0645\u0644\u0627\u062A \u0627\u0644\u0633\u0631\u064A\u0639\u0629"]},{type:"tip",text:"\u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u064A\u064F\u0648\u0641\u0651\u0631 '\u0631\u0623\u064A\u0627\u064B \u0645\u062D\u062F\u062F\u0627\u064B' (opinionated) \u2014 \u064A\u0639\u0646\u064A \u0647\u0646\u0627\u0643 \u0637\u0631\u064A\u0642\u0629 \u0648\u0627\u062D\u062F\u0629 \u0645\u0648\u0635\u0649 \u0628\u0647\u0627 \u0644\u0643\u0644 \u0634\u064A\u0621. \u0647\u0630\u0627 \u064A\u064F\u0642\u0644\u0651\u0644 \u0627\u0644\u0627\u062E\u062A\u064A\u0627\u0631\u0627\u062A \u0648\u064A\u064F\u0648\u062D\u0651\u062F \u0627\u0644\u0643\u0648\u062F \u0641\u064A \u0627\u0644\u0641\u0631\u0642 \u0627\u0644\u0643\u0628\u064A\u0631\u0629."},{type:"heading",text:"6. \u0645\u062A\u0649 \u062A\u0633\u062A\u062E\u062F\u0645 \u0623\u0646\u062C\u0648\u0644\u0627\u0631"},{type:"paragraph",text:"\u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0644\u064A\u0633 \u0627\u0644\u062E\u064A\u0627\u0631 \u0627\u0644\u0623\u0645\u062B\u0644 \u062F\u0627\u0626\u0645\u0627\u064B \u2014 \u0627\u062E\u062A\u0631\u0652\u0647 \u0639\u0646\u062F\u0645\u0627 \u062A\u0646\u0637\u0628\u0642 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637:"},{type:"list",items:["\u2705 \u062A\u0637\u0628\u064A\u0642 \u0645\u0624\u0633\u0633\u064A \u0643\u0628\u064A\u0631 \u064A\u062D\u062A\u0627\u062C \u0627\u062A\u0633\u0627\u0642\u0627\u064B \u0639\u0644\u0649 \u0645\u062F\u0649 \u0633\u0646\u0648\u0627\u062A","\u2705 \u0641\u0631\u064A\u0642 \u0643\u0628\u064A\u0631 \u064A\u062D\u062A\u0627\u062C \u0642\u0648\u0627\u0639\u062F \u0648\u0627\u0636\u062D\u0629 \u0648\u0647\u064A\u0643\u0644 \u0645\u062D\u062F\u062F","\u2705 TypeScript \u0648\u0645\u0628\u0627\u062F\u0626 OOP \u062C\u0632\u0621 \u0623\u0633\u0627\u0633\u064A \u0645\u0646 \u0627\u0644\u0645\u0634\u0631\u0648\u0639","\u2705 \u062A\u062D\u062A\u0627\u062C \u0643\u0644 \u0634\u064A\u0621 \u062C\u0627\u0647\u0632\u0627\u064B (Forms\u060C HTTP\u060C Router\u060C DI) \u0628\u062F\u0648\u0646 \u062A\u062C\u0645\u064A\u0639 \u0645\u0643\u062A\u0628\u0627\u062A","\u274C \u0645\u0648\u0642\u0639 \u0628\u0633\u064A\u0637 \u0623\u0648 \u0635\u0641\u062D\u0629 \u0647\u0628\u0648\u0637 \u2014 \u0627\u0633\u062A\u062E\u062F\u0645 HTML/CSS \u0623\u0648 Astro","\u274C \u0645\u0634\u0631\u0648\u0639 \u0635\u063A\u064A\u0631 \u0628\u0641\u0631\u064A\u0642 \u0648\u0627\u062D\u062F \u0623\u0648 \u0627\u062B\u0646\u064A\u0646 \u2014 React \u0623\u0648 Vue \u0623\u0628\u0633\u0637"]},{type:"warning",text:"\u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0644\u0647 \u0645\u0646\u062D\u0646\u0649 \u062A\u0639\u0644\u0651\u0645 \u0623\u0639\u0644\u0649 \u0645\u0646 React \u0648Vue. \u0644\u0643\u0646 \u0628\u0639\u062F \u0625\u062A\u0642\u0627\u0646\u0647\u060C \u0625\u0646\u062A\u0627\u062C\u064A\u062A\u0643 \u0641\u064A \u0627\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0627\u0644\u0643\u0628\u064A\u0631\u0629 \u0633\u062A\u0643\u0648\u0646 \u0623\u0639\u0644\u0649 \u0628\u0643\u062B\u064A\u0631."},{type:"heading",text:"7. \u0643\u064A\u0641 \u062A\u0633\u062A\u0641\u064A\u062F \u0645\u0646 \u0647\u0630\u0627 \u0627\u0644\u0643\u0648\u0631\u0633"},{type:"list",items:["\u0627\u0643\u062A\u0628 \u0627\u0644\u0643\u0648\u062F \u0628\u0646\u0641\u0633\u0643 \u2014 \u0644\u0627 \u062A\u0643\u062A\u0641\u0650 \u0628\u0627\u0644\u0642\u0631\u0627\u0621\u0629","\u0627\u0643\u0633\u0631 \u0627\u0644\u0623\u0634\u064A\u0627\u0621 \u0639\u0646 \u0642\u0635\u062F \u0648\u0634\u0627\u0647\u062F \u0645\u0627\u0630\u0627 \u064A\u062D\u062F\u062B","\u0623\u062C\u0628 \u0639\u0644\u0649 \u0623\u0633\u0626\u0644\u0629 \u0627\u0644\u0645\u0631\u0627\u062C\u0639\u0629 \u0628\u0643\u0644\u0645\u0627\u062A\u0643 \u0627\u0644\u062E\u0627\u0635\u0629","\u0623\u0646\u062C\u0632 \u0627\u0644\u0645\u0634\u0631\u0648\u0639\u064E\u064A\u0646 \u0643\u0627\u0645\u0644\u064E\u064A\u0646 \u062D\u062A\u0649 \u0627\u0644\u0646\u0634\u0631","\u062E\u0630 \u0641\u062A\u0631\u0627\u062A \u0631\u0627\u062D\u0629 \u2014 \u0627\u0644\u062F\u0645\u0627\u063A \u064A\u062D\u062A\u0627\u062C \u0648\u0642\u062A\u0627\u064B \u0644\u062A\u0631\u0633\u064A\u062E \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062A"]},{type:"tip",text:"\u0627\u0644\u0642\u0627\u0639\u062F\u0629 \u0627\u0644\u0630\u0647\u0628\u064A\u0629: \u0623\u0641\u0636\u0644 \u0637\u0631\u064A\u0642\u0629 \u0644\u0625\u062A\u0642\u0627\u0646 \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0647\u064A \u0627\u0644\u0628\u0646\u0627\u0621 \u0628\u0623\u0646\u062C\u0648\u0644\u0627\u0631."},{type:"heading",text:"\u2705 \u0645\u0644\u062E\u0635 \u0627\u0644\u0642\u0633\u0645"},{type:"list",items:["\u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0625\u0637\u0627\u0631 \u0639\u0645\u0644 \u0645\u062A\u0643\u0627\u0645\u0644 \u0645\u0646 Google \u2014 TypeScript \u0623\u0648\u0644\u0627\u064B","v22 \u064A\u064F\u0631\u0643\u0651\u0632 \u0639\u0644\u0649 Signals \u0643\u0637\u0631\u064A\u0642\u0629 \u0627\u0641\u062A\u0631\u0627\u0636\u064A\u0629 \u0644\u0625\u062F\u0627\u0631\u0629 \u0627\u0644\u062D\u0627\u0644\u0629","\u0627\u0644\u062C\u062F\u064A\u062F: Signal Forms\u060C OnPush \u0628\u0627\u0644\u0627\u0641\u062A\u0631\u0627\u0636\u064A\u060C Zoneless\u060C Resource API","\u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0645\u062B\u0627\u0644\u064A \u0644\u0644\u0641\u0631\u0642 \u0627\u0644\u0643\u0628\u064A\u0631\u0629 \u0648\u0627\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0637\u0648\u064A\u0644\u0629 \u0627\u0644\u0623\u0645\u062F","\u0633\u062A\u0628\u0646\u064A \u0645\u0634\u0631\u0648\u0639\u064E\u064A\u0646 \u0643\u0627\u0645\u0644\u064E\u064A\u0646 \u0641\u064A \u0646\u0647\u0627\u064A\u0629 \u0627\u0644\u0643\u0648\u0631\u0633"]},{type:"qa",question:"1. \u0628\u062C\u0645\u0644\u0629 \u0648\u0627\u062D\u062F\u0629\u060C \u0645\u0627 \u0627\u0644\u0641\u0631\u0642 \u0627\u0644\u0631\u0626\u064A\u0633\u064A \u0628\u064A\u0646 \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0648React\u061F",answer:"\u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0625\u0637\u0627\u0631 \u0639\u0645\u0644 \u0645\u062A\u0643\u0627\u0645\u0644 \u064A\u0648\u0641\u0631 \u0643\u0644 \u0634\u064A\u0621 \u062C\u0627\u0647\u0632\u0627\u064B (Forms\u060C HTTP\u060C Router\u060C DI)\u060C \u0628\u064A\u0646\u0645\u0627 React \u0645\u0643\u062A\u0628\u0629 \u0644\u0644\u0648\u0627\u062C\u0647\u0627\u062A \u0641\u0642\u0637 \u0648\u062A\u062D\u062A\u0627\u062C \u0644\u062A\u062C\u0645\u064A\u0639 \u0645\u0643\u062A\u0628\u0627\u062A \u062E\u0627\u0631\u062C\u064A\u0629."},{type:"qa",question:"2. \u0645\u0627 \u0623\u0628\u0631\u0632 \u062B\u0644\u0627\u062B\u0629 \u062A\u063A\u064A\u064A\u0631\u0627\u062A \u0641\u064A \u0623\u0646\u062C\u0648\u0644\u0627\u0631 v22\u061F",answer:"Signal Forms \u0645\u0633\u062A\u0642\u0631\u0629 \u0648\u0627\u0641\u062A\u0631\u0627\u0636\u064A\u0629\u060C OnPush \u0623\u0635\u0628\u062D\u062A \u0627\u0633\u062A\u0631\u0627\u062A\u064A\u062C\u064A\u0629 \u0627\u0644\u0643\u0634\u0641 \u0627\u0644\u0627\u0641\u062A\u0631\u0627\u0636\u064A\u0629\u060C \u0648Zoneless \u0647\u0648 \u0627\u0644\u0625\u0639\u062F\u0627\u062F \u0627\u0644\u0627\u0641\u062A\u0631\u0627\u0636\u064A \u0644\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0627\u0644\u062C\u062F\u064A\u062F\u0629."},{type:"qa",question:"3. \u0645\u062A\u0649 \u064A\u0643\u0648\u0646 \u0623\u0646\u062C\u0648\u0644\u0627\u0631 \u0627\u0644\u062E\u064A\u0627\u0631 \u0627\u0644\u0623\u0645\u062B\u0644\u061F",answer:"\u0639\u0646\u062F \u0628\u0646\u0627\u0621 \u062A\u0637\u0628\u064A\u0642\u0627\u062A \u0645\u0624\u0633\u0633\u064A\u0629 \u0643\u0628\u064A\u0631\u0629 \u0628\u0641\u0631\u0642 \u0636\u062E\u0645\u0629 \u062A\u062D\u062A\u0627\u062C \u0627\u062A\u0633\u0627\u0642\u0627\u064B \u0648\u0647\u064A\u0643\u0644\u0627\u064B \u0648\u0627\u0636\u062D\u0627\u064B \u0639\u0644\u0649 \u0645\u062F\u0649 \u0633\u0646\u0648\u0627\u062A\u060C \u0623\u0648 \u0639\u0646\u062F\u0645\u0627 \u064A\u0643\u0648\u0646 TypeScript \u0648\u0645\u0628\u0627\u062F\u0626 OOP \u062C\u0632\u0621\u0627\u064B \u0623\u0633\u0627\u0633\u064A\u0627\u064B \u0645\u0646 \u0627\u0644\u0645\u0634\u0631\u0648\u0639."}],contentEn:[{type:"heading",text:"\u{1F44B} Hello, I'm Mostafa Saqly"},{type:"paragraph",text:"I designed this course to help anyone learn Angular from scratch in a clear, structured way. I've gathered the best practices and modern techniques for Angular v22 all in one place \u2014 no scattered resources."},{type:"paragraph",text:"The idea is simple: save you time from browsing forums and watching dozens of videos. Everything you need is here \u2014 organized, concise, and immediately applicable."},{type:"cta",text:"Need one-on-one training on a complete learning path?",linkLabel:"Enter here \u2192",link:"https://saqly.com/individual-training"},{type:"tip",text:"Read and apply. Every lesson has practical examples you can run immediately on your machine."},{type:"heading",text:"1. What You Will Build"},{type:"paragraph",text:"By the end of this course you'll have built two complete applications ready for your portfolio: an Admin Dashboard and an E-Commerce Mini App \u2014 plus dozens of small examples covering every concept."},{type:"list",items:["\u{1F5C2}\uFE0F Project 1: Admin Dashboard \u2014 API data display, search, add/edit/delete, Signal Forms, route guards","\u{1F6D2} Project 2: E-Commerce Mini App \u2014 product pages, shopping cart, quantity management, local data persistence","\u26A1 Practice examples: Signals, HTTP, Routing, Forms, RxJS, SSR, and more"]},{type:"heading",text:"2. Prerequisites & Course Roadmap"},{type:"paragraph",text:"Problem: Many people start Angular with gaps in foundational knowledge and get frustrated at the first challenge. Angular is a complete framework \u2014 it builds on HTML, CSS, TypeScript, and object-oriented programming concepts."},{type:"paragraph",text:"Solution: Before starting, make sure you're comfortable with these fundamentals:"},{type:"list",items:["HTML & CSS \u2014 structure and styling","Basic TypeScript \u2014 types, interfaces, decorators","OOP concepts \u2014 classes and inheritance","Node.js (v22+) & npm \u2014 package management","Modern JavaScript \u2014 async/await, Promises, ES Modules"]},{type:"warning",text:"If TypeScript is completely unfamiliar, spend a couple of hours on the basics first. Angular is written in TypeScript, not plain JavaScript."},{type:"paragraph",text:"Course roadmap: 25 sections \u2014 from component fundamentals to deployment and testing \u2014 with two hands-on projects at the end."},{type:"heading",text:"3. Angular v22 Overview \u2014 The Signal-First Era"},{type:"paragraph",text:"Angular is a complete framework from Google for building enterprise web applications. Unlike React and Vue, Angular comes with everything built in: routing, forms, HTTP, testing, state management \u2014 no external libraries needed."},{type:"list",items:["Components \u2014 the fundamental building blocks, written in TypeScript + HTML + CSS","Signals \u2014 the new reactive system for efficient state management","Standalone Components \u2014 self-contained components without NgModule","Dependency Injection \u2014 the built-in DI system","Angular CLI \u2014 a powerful command-line tool to generate, build, and test"]},{type:"tip",text:"Angular v22 is called the 'Signal-First Era' because Signals are now the default way to manage state in any new component."},{type:"heading",text:"4. What's New in v22"},{type:"subheading",text:"\u26A1 Signal Forms \u2014 Stable in v22"},{type:"paragraph",text:"Problem: Angular forms were always complex \u2014 either Template-Driven (hard to test) or Reactive Forms (too much boilerplate). Signal Forms simplify everything."},{type:"paragraph",text:"Solution: Signal Forms are now the default approach in v22 \u2014 forms built on Signals, less code, easier to test."},{type:"code",code:`import { signalForm, Validators } from '@angular/forms';

// Signal Form \u2014 new in v22
const form = signalForm({
  name: ['', Validators.required],
  email: ['', [Validators.required, Validators.email]],
});

// Read the value as a Signal
console.log(form.value()); // { name: '', email: '' }`},{type:"subheading",text:"\u{1F3AF} OnPush as the Default Strategy"},{type:"paragraph",text:"In v22, every new component is created with OnPush change detection by default \u2014 better performance with zero extra effort. The old 'Default' strategy has been renamed to 'Eager'."},{type:"subheading",text:"\u{1F310} Zoneless by Default"},{type:"paragraph",text:"New projects in v22 no longer use Zone.js by default. This significantly improves performance and reduces bundle size."},{type:"list",items:["Signal Forms stable and the default approach","OnPush is the default change detection strategy","Zoneless is the default for new projects","Resource API stable (resource, rxResource, httpResource)","Selectorless Components \u2014 components without a selector (new)","Angular Aria \u2014 built-in accessibility support (stable)","Navigation API \u2014 Web Navigation API support in the Router"]},{type:"heading",text:"5. Angular vs React vs Vue"},{type:"paragraph",text:"Problem: Many ask 'what should I learn?' \u2014 the answer depends on the project type, team size, and context."},{type:"list",items:["Angular \u2014 complete framework, TypeScript-first, ideal for enterprise apps and large teams","React \u2014 UI library, high flexibility, massive ecosystem, ideal for startups and diverse projects","Vue \u2014 easy to learn, a blend of Angular and React, ideal for mid-size projects and quick integrations"]},{type:"tip",text:"Angular is 'opinionated' \u2014 there's one recommended way to do everything. This reduces choices and unifies code across large teams."},{type:"heading",text:"6. When to Use Angular"},{type:"paragraph",text:"Angular isn't always the best choice \u2014 pick it when these conditions apply:"},{type:"list",items:["\u2705 Large enterprise app that needs consistency over years","\u2705 Big team that needs clear rules and a defined structure","\u2705 TypeScript and OOP principles are core to the project","\u2705 You need everything ready (Forms, HTTP, Router, DI) without assembling libraries","\u274C Simple site or landing page \u2014 use plain HTML/CSS or Astro","\u274C Small project with one or two developers \u2014 React or Vue is simpler"]},{type:"warning",text:"Angular has a steeper learning curve than React and Vue. But once mastered, your productivity on large projects will be significantly higher."},{type:"heading",text:"7. How to Get the Most Out of This Course"},{type:"list",items:["Write the code yourself \u2014 don't just read","Break things on purpose and watch what happens","Answer review questions in your own words","Complete both projects through to deployment","Take breaks \u2014 your brain needs time to consolidate knowledge"]},{type:"tip",text:"Golden rule: the best way to master Angular is to build with Angular."},{type:"heading",text:"\u2705 Section Summary"},{type:"list",items:["Angular is a complete framework from Google \u2014 TypeScript-first","v22 focuses on Signals as the default state management approach","New: Signal Forms, OnPush by default, Zoneless, Resource API","Angular is ideal for large teams and long-term projects","You'll build two complete projects by the end of the course"]},{type:"qa",question:"1. In one sentence, what is the main difference between Angular and React?",answer:"Angular is a complete framework that provides everything out of the box (Forms, HTTP, Router, DI), while React is a UI library only and requires assembling external libraries."},{type:"qa",question:"2. What are the three most notable changes in Angular v22?",answer:"Signal Forms are stable and the default, OnPush is now the default change detection strategy, and Zoneless is the default setting for new projects."},{type:"qa",question:"3. When is Angular the best choice?",answer:"When building large enterprise applications with large teams that need consistency and a clear structure over many years, or when TypeScript and OOP principles are core to the project."}]};export{e as default};
